esqlQuery.esql:
TS metrics-mongodbreceiver.otel-default
// Scope to MongoDB OTel metrics
| WHERE data_stream.dataset == "mongodbreceiver.otel"
| WHERE metrics.mongodb.global_lock.time IS NOT NULL
// Rate of global lock time held (ms/sec); high rate indicates contention
| STATS lock_time_rate = SUM(RATE(metrics.mongodb.global_lock.time)) BY resource.attributes.server.address
// Alert when lock held >500ms/sec on average (adjust for your workload)
| WHERE lock_time_rate > 500
| SORT lock_time_rate DESC
| LIMIT 20
